#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    char ch;
    Node* next;
};

class Solution {
public:
bool deleteWord(Node* root, string word) {
    if (!root) return false;

    if (word[0] != root->ch) return false;

    if (word.size() == 1) {
        delete root;
        root = NULL;
        return true;
    }

    bool res = deleteWord(root->next, word.substr(1));

    if (!root->next) {
        delete root;
        root = NULL;
    }

    return res;
}
};

int main() {
    Solution solution;
    Node* root = new Node();
    root->ch = 'a';

    return 0;
}

