class Node:
    def __init__(self):
        self.ch = None
        self.next = None

class Solution:
    def deleteWord(self, root, word):
        if not root:
            return False

        if word[0] != root.ch:
            return False

        if len(word) == 1:
            root.next = None
            return True

        res = self.deleteWord(root.next, word[1:])

        if not root.next:
            del root

        return res

